/** DISTINCT tuple tracker backed by the primitive table for the common narrow projections. */
@Experimental
final class NativeDistinctTracker {

	static final AtomicLong PRIMITIVE_ROWS = new AtomicLong();
	static final AtomicLong OBJECT_ROWS = new AtomicLong();

	final int[] slots;
	final PrimitiveTupleTable primitive;
	final HashMap<GroupKey, Boolean> objects;
	final GroupKey probe;
	boolean emptySeen;
	long primitiveRows;
	long objectRows;
	boolean metricsCommitted;
	long[] batchHashState = new long[0];
	int[] batchHashes = new int[0];
	int[] batchBuckets = new int[0];
	int[] batchEntries = new int[0];

	NativeDistinctTracker(int[] slots) {
		this.slots = slots;
		this.primitive = slots.length >= 1 && slots.length <= 4 ? new PrimitiveTupleTable(slots.length, 256) : null;
		this.objects = primitive == null && slots.length > 0 ? new HashMap<>() : null;
		this.probe = objects == null ? null : new GroupKey(new long[slots.length]);
	}

	boolean add(long[] row) {
		if (slots.length == 0) {
			boolean fresh = !emptySeen;
			emptySeen = true;
			return fresh;
		}
		if (primitive != null) {
			int before = primitive.size;
			primitive.findOrInsert(row, slots, true);
			primitiveRows++;
			return primitive.size != before;
		}
		for (int i = 0; i < slots.length; i++) {
			long id = row[slots[i]];
			probe.ids[i] = id == NULL_CONTEXT_ID ? UNKNOWN : id;
		}
		probe.rehash();
		objectRows++;
		if (objects.containsKey(probe)) {
			return false;
		}
		objects.put(probe.storedCopy(), Boolean.TRUE);
		return true;
	}

	boolean add(NativeBatch batch, int row) {
		if (slots.length == 0) {
			boolean fresh = !emptySeen;
			emptySeen = true;
			return fresh;
		}
		if (primitive != null) {
			int before = primitive.size;
			primitive.findOrInsert(batch, row, slots, true);
			primitiveRows++;
			return primitive.size != before;
		}
		for (int i = 0; i < slots.length; i++) {
			long id = batch.get(slots[i], row);
			probe.ids[i] = id == NULL_CONTEXT_ID ? UNKNOWN : id;
		}
		probe.rehash();
		objectRows++;
		if (objects.containsKey(probe)) {
			return false;
		}
		objects.put(probe.storedCopy(), Boolean.TRUE);
		return true;
	}

	int selectBatch(NativeBatch batch, int[] selection, int count) {
		if (slots.length == 0) {
			if (count == 0 || emptySeen) {
				return 0;
			}
			emptySeen = true;
			return 1;
		}
		if (primitive == null) {
			int accepted = 0;
			for (int i = 0; i < count; i++) {
				int row = selection[i];
				if (add(batch, row)) {
					selection[accepted++] = row;
				}
			}
			return accepted;
		}
		ensureBatchCapacity(count);
		primitive.hashBatch(batch, selection, count, slots, true, batchHashState, batchHashes);
		primitive.headBatch(batchHashes, count, batchBuckets, batchEntries);
		long preparedVersion = primitive.version;
		primitiveRows += count;
		int accepted = 0;
		for (int i = 0; i < count; i++) {
			int row = selection[i];
			int before = primitive.size;
			int existing = primitive.findPrepared(batch, row, slots, true, batchHashes[i], batchBuckets[i],
					batchEntries[i], preparedVersion);
			if (existing < 0) {
				primitive.findOrInsertHashed(batch, row, slots, true, batchHashes[i]);
			}
			if (primitive.size != before) {
				selection[accepted++] = row;
			}
		}
		return accepted;
	}

	private void ensureBatchCapacity(int capacity) {
		if (batchHashes.length >= capacity) {
			return;
		}
		batchHashState = new long[capacity];
		batchHashes = new int[capacity];
		batchBuckets = new int[capacity];
		batchEntries = new int[capacity];
	}

	void commitMetrics() {
		if (metricsCommitted) {
			return;
		}
		metricsCommitted = true;
		PRIMITIVE_ROWS.addAndGet(primitiveRows);
		OBJECT_ROWS.addAndGet(objectRows);
	}

	void clear() {
		emptySeen = false;
		if (primitive != null) {
			primitive.clear();
		} else if (objects != null) {
			objects.clear();
		}
	}
}

/** DISTINCT tracker that uses a proven order frontier instead of retaining every projected tuple. */
@Experimental
final class NativeOrderedDistinctTracker {

	final NativeTupleDistinctPlan plan;
	final NativeDistinctTracker residual;
	final long[] previous;
	boolean initialized;
	boolean emptySeen;

	NativeOrderedDistinctTracker(NativeTupleDistinctPlan plan) {
		this.plan = plan;
		this.residual = plan.strategy == NativeDistinctStrategy.GLOBAL_HASH
				? new NativeDistinctTracker(plan.keySlots)
				: plan.strategy == NativeDistinctStrategy.PARTITIONED_HASH
						? new NativeDistinctTracker(plan.residualSlots)
						: null;
		int previousWidth = plan.strategy == NativeDistinctStrategy.ADJACENT ? plan.keySlots.length
				: plan.partitionSlots.length;
		this.previous = new long[previousWidth];
	}

	boolean add(long[] row) {
		boolean fresh = switch (plan.strategy) {
		case GLOBAL_HASH -> residual.add(row);
		case ADJACENT -> transition(row, plan.keySlots);
		case PARTITIONED_HASH -> {
			if (transition(row, plan.partitionSlots)) {
				residual.clear();
			}
			yield residual.add(row);
		}
		};
		if (plan.keySlots.length == 0 && fresh) {
			emptySeen = true;
		}
		return fresh;
	}

	int selectBatch(NativeBatch batch, int[] selection, int count) {
		if (plan.strategy == NativeDistinctStrategy.GLOBAL_HASH) {
			int accepted = residual.selectBatch(batch, selection, count);
			if (plan.keySlots.length == 0 && accepted > 0) {
				emptySeen = true;
			}
			return accepted;
		}
		int accepted = 0;
		for (int i = 0; i < count; i++) {
			int row = selection[i];
			boolean fresh = switch (plan.strategy) {
			case GLOBAL_HASH -> throw new AssertionError();
			case ADJACENT -> transition(batch, row, plan.keySlots);
			case PARTITIONED_HASH -> {
				if (transition(batch, row, plan.partitionSlots)) {
					residual.clear();
				}
				yield residual.add(batch, row);
			}
			};
			if (fresh) {
				selection[accepted++] = row;
			}
		}
		if (plan.keySlots.length == 0 && accepted > 0) {
			emptySeen = true;
		}
		return accepted;
	}

	void commitMetrics() {
		if (residual != null) {
			residual.commitMetrics();
		}
	}

	private boolean transition(long[] row, int[] slots) {
		boolean changed = !initialized;
		for (int i = 0; i < slots.length; i++) {
			long value = normalize(row[slots[i]]);
			if (!changed && previous[i] != value) {
				changed = true;
			}
		}
		if (changed) {
			for (int i = 0; i < slots.length; i++) {
				previous[i] = normalize(row[slots[i]]);
			}
			initialized = true;
		}
		return changed;
	}

	private boolean transition(NativeBatch batch, int row, int[] slots) {
		boolean changed = !initialized;
		for (int i = 0; i < slots.length; i++) {
			long value = normalize(batch.get(slots[i], row));
			if (!changed && previous[i] != value) {
				changed = true;
			}
		}
		if (changed) {
			for (int i = 0; i < slots.length; i++) {
				previous[i] = normalize(batch.get(slots[i], row));
			}
			initialized = true;
		}
		return changed;
	}

	private long normalize(long value) {
		return value == NULL_CONTEXT_ID ? UNKNOWN : value;
	}
}
